using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// --- 1. Getting strongly-typed JsonTypeInfo<T> ---

var options = JsonSerializerOptions.Default;

// Generic overload returns JsonTypeInfo<T> directly — no cast needed.
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"1) Got JsonTypeInfo<{personInfo.Type.Name}>  (kind: {personInfo.Kind})");

// --- 2. Probing without throwing ---

// TryGetTypeInfo returns false instead of throwing when metadata isn't available.
// Use a context that only knows about Person.
var limited = new JsonSerializerOptions { TypeInfoResolver = PersonOnlyContext.Default };

if (limited.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? found))
{
    // Safe downcast — GetTypeInfo(typeof(T)) always yields JsonTypeInfo<T>.
    var typed = (JsonTypeInfo<Person>)found!;
    Console.WriteLine($"2a) Probe for Person succeeded  (props: {typed.Properties.Count})");
}

if (!limited.TryGetTypeInfo(typeof(Order), out _))
{
    Console.WriteLine("2b) Probe for Order returned false — no exception thrown");
}

// --- Types used above ---

public record Person(string Name, int Age);
public record Order(int Id, decimal Total);

[JsonSerializable(typeof(Person))]
public partial class PersonOnlyContext : JsonSerializerContext;

